import os
import psutil

def close_all_applications():
    # Alle laufenden Prozesse abrufen
    for process in psutil.process_iter(['pid', 'name']):
        try:
            # Prozessname und PID abrufen
            process_name = process.info['name']
            process_id = process.info['pid']

            # Prozess beenden (außer Systemprozesse)
            if process_name not in ['System Idle Process', 'System']:
                print(f"Schließe Prozess: {process_name} (PID: {process_id})")
                os.system(f"taskkill /PID {process_id} /F")
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

if __name__ == "__main__":
    close_all_applications()
