def calculate_password_strength(password):
    score = 0
    length = len(password)

    # Länge des Passworts
    if length >= 8:
        score += 1
    if length >= 12:
        score += 1
    if length >= 16:
        score += 1

    # Kleinbuchstaben
    if any(c.islower() for c in password):
        score += 1

    # Großbuchstaben
    if any(c.isupper() for c in password):
        score += 1

    # Zahlen
    if any(c.isdigit() for c in password):
        score += 1

    # Sonderzeichen
    special_chars = "!@#$%^&*()_+-=[]{}|;:,.<>?"
    if any(c in special_chars for c in password):
        score += 1

    # Bewertung
    if score <= 2:
        return "Sehr schwach"
    elif score <= 3:
        return "Schwach"
    elif score <= 4:
        return "Mittel"
    elif score <= 5:
        return "Stark"
    else:
        return "Sehr stark"

# Beispiel
password = "Passwort123!"
print(calculate_password_strength(password))
