import requests
from bs4 import BeautifulSoup
import re

def search_harmful_chemical_applications():
    # Suchbegriffe für schädliche Chemikalien und industrielle Anwendungen
    keywords = [
        "schädliche Chemikalien industrielle Anwendung",
        "Gefahrstoffe in der Industrie",
        "Toxische Chemikalien Prozessindustrie",
        "Hazardous chemicals industrial use",
        "Industrial applications of toxic chemicals"
    ]

    results = []

    for keyword in keywords:
        try:
            # Google-Suche URL (ohne API, daher nur Beispiel)
            search_url = f"https://www.google.com/search?q={keyword}"
            headers = {
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36"
            }
            response = requests.get(search_url, headers=headers)

            if response.status_code == 200:
                soup = BeautifulSoup(response.text, 'html.parser')
                # Extrahiere Suchergebnisse
                for link in soup.find_all('a', href=True):
                    href = link['href']
                    if href.startswith('/url?q='):
                        url = href.split('/url?q=')[1].split('&')[0]
                        if url.startswith('http'):
                            results.append(url)
        except Exception as e:
            print(f"Fehler bei der Suche nach '{keyword}': {e}")

    # Filtere Ergebnisse auf relevante Seiten
    relevant_results = []
    for url in results:
        try:
            response = requests.get(url, headers=headers, timeout=10)
            if response.status_code == 200:
                content = response.text.lower()
                # Suchen nach Begriffen wie "industrie", "anwendung", "prozess"
                if any(word in content for word in ['industrie', 'anwendung', 'prozess']):
                    relevant_results.append(url)
        except Exception as e:
            print(f"Fehler beim Abrufen von {url}: {e}")

    return relevant_results

# Beispielaufruf
if __name__ == "__main__":
    print("Suche nach Anwendungen schädlicher Chemikalien in industriellen Prozessen...")
    results = search_harmful_chemical_applications()
    for result in results:
        print(result)
